const ESTOQUE_DATA = Object.fromEntries(Object.entries(_ER).map(([g,items])=>[g,items.map(r=>({nome:r[0],qtd_estoque:r[1],custo_unit:r[2]}))]));

// -- Componente de linha com busca inline -----------------------------------
function SearchRow({ row, onUpdate, onUpdateBatch, onRemove, sectionType, isFirst }) {
  const [query, setQuery]   = useState("");
  const [open, setOpen]     = useState(false);
  const [manual, setManual] = useState(!!row._manual);

  const toggleManual = () => {
    const next = !manual;
    setManual(next);
    onUpdate("_manual", next ? "1" : "");
    // clear lookup fields when switching to manual so custo re-calculates from vunit_manual
    if (next) { setQuery(""); setOpen(false); }
  };

  const acColor = sectionType==="mo" ? "#3b88c3" : sectionType==="eq" ? "#2e9c8c" : "#8c6fd4";

  const ModeBtn = () => (
    <div style={{display:"flex",alignItems:"center",gap:4,marginBottom:6}}>
      <div onClick={toggleManual}
        style={{display:"flex",alignItems:"center",gap:5,cursor:"pointer",padding:"3px 8px",borderRadius:4,
          background: manual?"#3d2a0a":"#1e3045",border:`1px solid ${manual?"#e0a030":brd}`,
          fontSize:"0.65rem",fontWeight:700,color:manual?"#e0a030":mut,userSelect:"none"}}>
        {manual ? "manual" : "busca"}
      </div>
    </div>
  );

  // -- MAO DE OBRA ----------------------------------------------------------
  if (sectionType === "mo") {
    const matches  = MO_DATA.filter(m => m.funcao.toLowerCase().includes(query.toLowerCase())).slice(0,8);
    const selected = MO_DATA.find(m => m.funcao === row.funcao);
    const vm       = manual ? (parseFloat(row.vunit_manual)||0) : (selected ? selected.valor_mes : 0);
    const custo    = vm * (parseFloat(row.meses)||0) * (parseFloat(row.qtd)||0);
    return (
      <div style={{background:"#0a1520",borderRadius:6,padding:"10px 12px",marginBottom:6,border:`1px solid ${brd}`}}>
        <ModeBtn />
        <div style={{display:"grid",gridTemplateColumns:"2fr 80px 80px 80px 80px 32px",gap:6,alignItems:"end"}}>
          <div>
            {isFirst && <Lbl>Funcao</Lbl>}
            {manual ? (
              <Inp value={row.funcao} placeholder="Funcao livre..." onChange={e=>onUpdate("funcao",e.target.value)} />
            ) : (
              <div style={{position:"relative"}}>
                <Inp value={query||row.funcao} placeholder="Pesquisar funcao..."
                  onChange={e=>{setQuery(e.target.value);setOpen(true);}}
                  onFocus={()=>setOpen(true)} sx={{borderColor:selected?"#3b88c3":brd}} />
                {open && query && (
                  <div style={_dd180}>
                    {matches.length===0 && <div style={{padding:"8px 12px",color:mut,fontSize:"0.75rem"}}>Sem resultado</div>}
                    {matches.map(m=>(
                      <div key={m.cod} onClick={()=>{onUpdate("funcao",m.funcao);setQuery("");setOpen(false);}}
                        style={{padding:"8px 12px",cursor:"pointer",fontSize:"0.76rem",color:tx,borderBottom:`1px solid ${brd}22`}}
                        onMouseOver={e=>e.currentTarget.style.background="#1e3045"} onMouseOut={e=>e.currentTarget.style.background="transparent"}>
                        <span style={{fontWeight:700,color:"#3b88c3"}}>{m.funcao}</span>
                        <span style={{color:mut,marginLeft:8,fontSize:"0.68rem"}}>R$ {m.valor_mes.toLocaleString("pt-BR",{minimumFractionDigits:2})}/mes</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
          <div>
            {isFirst && <Lbl>Meses</Lbl>}
            <Inp type="number" value={row.meses} placeholder="0" onChange={e=>onUpdate("meses",e.target.value)} />
          </div>
          <div>
            {isFirst && <Lbl>Qtd.</Lbl>}
            <Inp type="number" value={row.qtd} placeholder="0" onChange={e=>onUpdate("qtd",e.target.value)} />
          </div>
          <div>
            {isFirst && <Lbl>{manual?"Vl/Mes":"Vl/Mes ref."}</Lbl>}
            {manual
              ? <Inp type="number" value={row.vunit_manual} placeholder="0,00" onChange={e=>onUpdate("vunit_manual",e.target.value)} />
              : <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"8px 10px",fontSize:"0.76rem",color:selected?"#3b88c3":mut}}>
                  {selected ? "R$ "+selected.valor_mes.toLocaleString("pt-BR",{minimumFractionDigits:2}) : "-"}
                </div>
            }
          </div>
          <div>
            {isFirst && <Lbl>Custo</Lbl>}
            <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"8px 10px",fontSize:"0.76rem",fontWeight:700,color:custo>0?"#4dcb8a":mut}}>
              {custo>0 ? "R$ "+fmtN(custo) : "-"}
            </div>
          </div>
          <div style={{display:"flex",alignItems:isFirst?"flex-end":"center"}}>
            <Btn v="d" sx={{padding:"6px 9px",fontSize:"0.9rem"}} onClick={onRemove}>X</Btn>
          </div>
        </div>
        <div style={{marginTop:6}}>
          <Inp value={row.obs} placeholder="Obs..." onChange={e=>onUpdate("obs",e.target.value)} sx={{fontSize:"0.74rem"}} />
        </div>
      </div>
    );
  }

  // -- EQUIPAMENTOS ---------------------------------------------------------
  if (sectionType === "eq") {
    const matches  = EQ_DATA.filter(e => (e.item+" "+e.fornecedor).toLowerCase().includes(query.toLowerCase())).slice(0,8);
    const selected = EQ_DATA.find(e => e.item === row.item);
    const vu       = manual ? (parseFloat(row.vunit_manual)||0) : (selected ? selected.valor_unit : 0);
    const custo    = vu * (parseFloat(row.qtd)||0);
    return (
      <div style={{background:"#0a1520",borderRadius:6,padding:"10px 12px",marginBottom:6,border:`1px solid ${brd}`}}>
        <ModeBtn />
        <div style={{display:"grid",gridTemplateColumns:"2.5fr 70px 90px 110px 32px",gap:6,alignItems:"end"}}>
          <div>
            {isFirst && <Lbl>Equipamento / Fornecedor</Lbl>}
            {manual ? (
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:4}}>
                <Inp value={row.item} placeholder="Equipamento..." onChange={e=>onUpdate("item",e.target.value)} />
                <Inp value={row.fornecedor} placeholder="Fornecedor..." onChange={e=>onUpdate("fornecedor",e.target.value)} />
              </div>
            ) : (
              <div style={{position:"relative"}}>
                <Inp value={query||row.item} placeholder="Pesquisar equipamento..."
                  onChange={e=>{setQuery(e.target.value);setOpen(true);}}
                  onFocus={()=>setOpen(true)} sx={{borderColor:selected?"#2e9c8c":brd}} />
                {open && query && (
                  <div style={_dd180}>
                    {matches.length===0 && <div style={{padding:"8px 12px",color:mut,fontSize:"0.75rem"}}>Sem resultado</div>}
                    {matches.map((e,i)=>(
                      <div key={i} onClick={()=>{onUpdateBatch({item:e.item,fornecedor:e.fornecedor,valor_unit:String(e.valor_unit),unidade:e.unidade});setQuery("");setOpen(false);}}
                        style={{padding:"8px 12px",cursor:"pointer",borderBottom:`1px solid ${brd}22`}}
                        onMouseOver={ev=>ev.currentTarget.style.background="#1e3045"} onMouseOut={ev=>ev.currentTarget.style.background="transparent"}>
                        <div style={{fontSize:"0.76rem",color:tx,fontWeight:700}}>{e.item}</div>
                        <div style={{fontSize:"0.65rem",color:mut}}>{e.fornecedor} - R$ {e.valor_unit.toLocaleString("pt-BR",{minimumFractionDigits:2})}/{e.unidade}</div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
          <div>
            {isFirst && <Lbl>Qtd</Lbl>}
            <Inp type="number" value={row.qtd} placeholder="0" onChange={e=>onUpdate("qtd",e.target.value)} />
          </div>
          <div>
            {isFirst && <Lbl>{manual?"Vlr.Un. / Un.":"Un. / Vlr.Un."}</Lbl>}
            {manual ? (
              <div style={{display:"grid",gridTemplateColumns:"1fr 60px",gap:4}}>
                <Inp type="number" value={row.vunit_manual} placeholder="0,00" onChange={e=>onUpdate("vunit_manual",e.target.value)} />
                <Inp value={row.unidade} placeholder="un" onChange={e=>onUpdate("unidade",e.target.value)} />
              </div>
            ) : (
              <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"8px 10px",fontSize:"0.72rem",color:selected?"#2e9c8c":mut}}>
                {selected ? selected.unidade+" / R$ "+fmtN(selected.valor_unit) : "-"}
              </div>
            )}
          </div>
          <div>
            {isFirst && <Lbl>Custo Total</Lbl>}
            <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"8px 10px",fontSize:"0.76rem",fontWeight:700,color:custo>0?"#4dcb8a":mut}}>
              {custo>0 ? "R$ "+fmtN(custo) : "-"}
            </div>
          </div>
          <div style={{display:"flex",alignItems:isFirst?"flex-end":"center"}}>
            <Btn v="d" sx={{padding:"6px 9px",fontSize:"0.9rem"}} onClick={onRemove}>X</Btn>
          </div>
        </div>
      </div>
    );
  }

  // -- INSUMOS / MATERIAL ----------------------------------------------------
  if (sectionType === "estoque") {
    const grp      = row.grupo || "";
    const itensGrp = grp ? (ESTOQUE_DATA[grp]||[]) : [];
    // inputText drives the filter; when empty shows saved nome as placeholder
    const inputText = query;
    const matches  = grp && inputText
      ? itensGrp.filter(it => it.nome.toLowerCase().includes(inputText.toLowerCase())).slice(0,10)
      : [];
    const vu    = manual ? (parseFloat(row.vunit_manual)||0) : (parseFloat(row.custo_unit)||0);
    const custo = vu * (parseFloat(row.qtd)||0);
    return (
      <div style={{background:"#0a1520",borderRadius:6,padding:"10px 12px",marginBottom:6,border:`1px solid ${brd}`}}>
        <ModeBtn />
        <div style={{display:"grid",gridTemplateColumns:"120px 2fr 80px 80px 110px 32px",gap:6,alignItems:"end"}}>
          <div>
            {isFirst && <Lbl>Grupo</Lbl>}
            <Sel value={grp} onChange={e=>{onUpdateBatch({grupo:e.target.value,nome:"",qtd_estoque:"",custo_unit:""});setQuery("");setOpen(false);}}>
              <option value="">-- Grupo --</option>
              {ESTOQUE_GRUPOS.map(g=><option key={g} value={g}>{g}</option>)}
              {manual && <option value="OUTRO">OUTRO</option>}
            </Sel>
          </div>
          <div>
            {isFirst && <Lbl>Item</Lbl>}
            {manual ? (
              <Inp value={row.nome} placeholder="Descricao do item..." onChange={e=>onUpdate("nome",e.target.value)} />
            ) : (
              <div style={{position:"relative"}}>
                <Inp
                  value={inputText}
                  placeholder={row.nome || (grp ? "Pesquisar item..." : "Selecione um grupo")}
                  disabled={!grp}
                  onChange={e=>{setQuery(e.target.value);setOpen(true);}}
                  onFocus={()=>{setOpen(true);}}
                  sx={{borderColor:row.nome?"#8c6fd4":brd,opacity:grp?1:0.5,
                       fontStyle:inputText?"normal":"italic",color:inputText?tx:row.nome?sub:mut}} />
                {open && inputText && grp && (
                  <div style={_dd200}>
                    {matches.length===0
                      ? <div style={{padding:"8px 12px",color:mut,fontSize:"0.75rem"}}>Sem resultado para "{inputText}"</div>
                      : matches.map((it,i)=>(
                          <div key={i}
                            onMouseDown={e=>{
                              e.preventDefault();
                              onUpdateBatch({nome:it.nome,qtd_estoque:String(it.qtd_estoque),custo_unit:String(it.custo_unit)});
                              setQuery("");
                              setOpen(false);
                            }}
                            style={{padding:"8px 12px",cursor:"pointer",borderBottom:`1px solid ${brd}22`}}
                            onMouseOver={ev=>ev.currentTarget.style.background="#1e3045"}
                            onMouseOut={ev=>ev.currentTarget.style.background="transparent"}>
                            <div style={{fontSize:"0.74rem",color:tx}}>{it.nome}</div>
                            <div style={{fontSize:"0.65rem",color:mut}}>Estoque: {it.qtd_estoque} - R$ {it.custo_unit.toLocaleString("pt-BR",{minimumFractionDigits:2})}/un</div>
                          </div>
                        ))
                    }
                  </div>
                )}
              </div>
            )}
          </div>
          <div>
            {isFirst && <Lbl>Estoque</Lbl>}
            <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"8px 10px",fontSize:"0.72rem",color:row.nome?"#8c6fd4":mut}}>
              {manual ? "-" : (row.qtd_estoque||"-")}
            </div>
          </div>
          <div>
            {isFirst && <Lbl>Qtd Usar</Lbl>}
            <Inp type="number" value={row.qtd} placeholder="0" onChange={e=>onUpdate("qtd",e.target.value)} />
          </div>
          <div>
            {isFirst && <Lbl>{manual?"Vlr.Un.":"Custo"}</Lbl>}
            {manual
              ? <Inp type="number" value={row.vunit_manual} placeholder="0,00" onChange={e=>onUpdate("vunit_manual",e.target.value)} />
              : <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"8px 10px",fontSize:"0.76rem",fontWeight:700,color:custo>0?"#4dcb8a":mut}}>
                  {custo>0 ? "R$ "+fmtN(custo) : "-"}
                </div>
            }
          </div>
          <div style={{display:"flex",alignItems:isFirst?"flex-end":"center"}}>
            <Btn v="d" sx={{padding:"6px 9px",fontSize:"0.9rem"}} onClick={onRemove}>X</Btn>
          </div>
        </div>
        {manual && custo>0 && (
          <div style={{marginTop:6,display:"flex",justifyContent:"flex-end"}}>
            <div style={{background:bg,border:`1px solid ${brd}`,borderRadius:6,padding:"6px 12px",fontSize:"0.74rem",fontWeight:700,color:"#4dcb8a"}}>
              Custo: R$ {fmtN(custo)}
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
}

function SmartSection({ title, ac, items, onChange, sectionType, addLbl }) {
  const blankMo    = {funcao:"",meses:"",qtd:"",obs:""};
  const blankEq    = {item:"",fornecedor:"",qtd:"",valor_unit:"",unidade:""};
  const blankStock = {grupo:"",nome:"",qtd_estoque:"",custo_unit:"",qtd:""};
  const blank = sectionType==="mo" ? blankMo : sectionType==="eq" ? blankEq : blankStock;

  const add = () => onChange([...items, {...blank}]);
  const rm  = i => onChange(items.filter((_,j)=>j!==i));
  const upd = (i,k,v) => { const n=[...items]; n[i]={...n[i],[k]:v}; onChange(n); };
  const updBatch = (i, patch) => { const n=[...items]; n[i]={...n[i],...patch}; onChange(n); };

  // cost totals
  const total = items.reduce((s,row) => {
    if (sectionType==="mo") {
      const vm = row._manual ? (parseFloat(row.vunit_manual)||0) : (MO_DATA.find(x=>x.funcao===row.funcao)?.valor_mes||0);
      return s + vm*(parseFloat(row.meses)||0)*(parseFloat(row.qtd)||0);
    }
    if (sectionType==="eq") {
      const vu = row._manual ? (parseFloat(row.vunit_manual)||0) : (EQ_DATA.find(x=>x.item===row.item)?.valor_unit||0);
      return s + vu*(parseFloat(row.qtd)||0);
    }
    const vu = row._manual ? (parseFloat(row.vunit_manual)||0) : (parseFloat(row.custo_unit)||0);
    return s + vu*(parseFloat(row.qtd)||0);
  },0);

  return (
    <div style={{background:card,border:`1px solid ${brd}`,borderLeft:`3px solid ${ac}`,borderRadius:8,padding:"12px 16px",marginBottom:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
        <div style={{fontSize:"0.68rem",fontWeight:700,color:ac,letterSpacing:"0.1em",textTransform:"uppercase"}}>{title}</div>
        {total>0 && <div style={{fontSize:"0.75rem",color:"#4dcb8a",fontWeight:700}}>Total: R$ {fmtN(total)}</div>}
      </div>
      {items.map((row,i) => (
        <SearchRow key={i} row={row} onUpdate={(k,v)=>upd(i,k,v)} onUpdateBatch={patch=>updBatch(i,patch)} onRemove={()=>rm(i)} sectionType={sectionType} isFirst={i===0} />
      ))}
      <Btn v="g" onClick={add} sx={{marginTop:4,fontSize:"0.74rem"}}>+ {addLbl}</Btn>
    </div>
  );
}

function DynList({items, onChange, cols, addLbl}) {
  const add = () => onChange([...items, Object.fromEntries(cols.map(c=>[c.k,""]))]);
  const rm  = i => onChange(items.filter((_,j)=>j!==i));
  const upd = (i,k,v) => { const n=[...items]; n[i]={...n[i],[k]:v}; onChange(n); };
  return (
    <div>
      {items.map((row,i) => (
        <div key={i} style={{display:"grid",gridTemplateColumns:cols.map(c=>c.w||"1fr").join(" ")+" 32px",gap:6,alignItems:"end",marginBottom:6}}>
          {cols.map(col => (
            <div key={col.k}>
              {i===0 && <Lbl>{col.lbl}</Lbl>}
              {col.type==="sel"
                ? <Sel value={row[col.k]} onChange={e=>upd(i,col.k,e.target.value)}><option value="">--</option>{col.opts.map(o=><option key={o} value={o}>{o}</option>)}</Sel>
                : <Inp type={col.type||"text"} value={row[col.k]} placeholder={col.ph||""} onChange={e=>upd(i,col.k,e.target.value)} />
              }
            </div>
          ))}
          <div style={{display:"flex",alignItems:i===0?"flex-end":"center"}}>
            <Btn v="d" sx={{padding:"6px 9px",fontSize:"0.9rem"}} onClick={()=>rm(i)}>X</Btn>
          </div>
        </div>
      ))}
      <Btn v="g" onClick={add} sx={{marginTop:4,fontSize:"0.74rem"}}>+ {addLbl}</Btn>
    </div>
  );
}

const BLANK = {qtd_executar:"",linha_plan:"",status:"",descricao_extra:"",observacao:"",mao_de_obra:[],equipamentos:[],insumos:[],materiais:[],subcontratadas:[]};

// - helper: compute receita for one queue entry + its extra
function calcReceita(entry, extra) {
  if (!extra) return 0;
  const pm = PRICE_MAP[entry.code];
  if (!pm) return 0;
  const qEx  = parseFloat(extra.qtd_executar) || 0;
  const qRef = parseFloat(entry.qtd) || 0;
  const q = qEx > 0 ? qEx : qRef;
  return q > 0 ? pm.price * q : 0;
}

// - Page 2: Consolidated dashboard -
// Receita PLANEJADA por sistema: valor PARA da DE_PARA (Pr.Un x Qtd PARA)
// distribuido proporcionalmente pela qtd de cada linha do DADOS_SISTEMAS
const RECEITA_PLAN_SIS = {"DIESEL 50 NVS":25747.2,"DIESEL 50 CIAS":3326.54,"DIESEL 500 NVS":1086972.51,"DIESEL 500 CIAS":30487.43,"NAFTA":361441.21,"GLP":91190.33,"DILUENTES":281203.34,"PETROLEO":169332.45,"SLOP":469441.65,"EFLUENTES":0,"OCREF":200846.47,"SCI":96002.72,"GERAL":0,"OUTROS":6640903.49,"ESTRUTURA METALICA":7240898.49};
const PLAN_TOTAL = Object.values(RECEITA_PLAN_SIS).reduce((a,b)=>a+b,0);

// Receita planejada por item: Pr.Un x Qtd PARA (proporcional ao peso do item no sistema)
// Para o bloco de cabecalho do item, usamos Pr.Un x Qtd PARA do item - nao disponivel por item,
// entao mostramos apenas o Pr.Un. unitario que esta correto.
// calcReceitaRef agora retorna 0 (nao usamos mais qtd planilha como referencia de valor)
function calcReceitaRef() { return 0; } // descontinuado - referencia agora e RECEITA_PLAN_SIS

function fmtM(v) {
  if (v >= 1e9) return "R$ " + (v/1e9).toFixed(2).replace(".",",") + " Bi";
  if (v >= 1e6) return "R$ " + (v/1e6).toFixed(2).replace(".",",") + " Mi";
  return "R$ " + fmtN(v);
}

function BarGroup({ label, refVal, validVal, maxVal, color }) {
  const refW  = maxVal > 0 ? Math.min(refVal/maxVal*100,  100) : 0;
  const valW  = maxVal > 0 ? Math.min(validVal/maxVal*100,100) : 0;
  const diff  = validVal - refVal;
  const diffPct = refVal > 0 ? (diff/refVal*100) : 0;
  const diffColor = diff > 0 ? "#4dcb8a" : diff < 0 ? "#e05a5a" : mut;
  return (
    <div style={{marginBottom:18}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5,flexWrap:"wrap",gap:4}}>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          <div style={{width:10,height:10,borderRadius:2,background:color,flexShrink:0}} />
          <span style={{fontSize:"0.78rem",color:tx,fontWeight:600}}>{label}</span>
        </div>
        {validVal > 0 && (
          <div style={{fontSize:"0.68rem",color:diffColor,fontWeight:700}}>
            {diff > 0 ? "+" : ""}{diffPct.toFixed(1)}% vs ref.
          </div>
        )}
      </div>
      {/* Barra referencia */}
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:3}}>
        <div style={{width:60,fontSize:"0.6rem",color:mut,textAlign:"right",flexShrink:0}}>Referencia</div>
        <div style={{flex:1,height:8,background:"#1e3045",borderRadius:4,overflow:"hidden"}}>
          <div style={{width:`${refW}%`,height:"100%",background:color,opacity:0.4,borderRadius:4}} />
        </div>
        <div style={{width:90,fontSize:"0.7rem",color:sub,textAlign:"right",flexShrink:0}}>{fmtM(refVal)}</div>
      </div>
      {/* Barra validada */}
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        <div style={{width:60,fontSize:"0.6rem",color:"#4dcb8a",textAlign:"right",flexShrink:0}}>Validada</div>
        <div style={{flex:1,height:8,background:"#1e3045",borderRadius:4,overflow:"hidden"}}>
          <div style={{width:`${valW}%`,height:"100%",background:"#4dcb8a",borderRadius:4,transition:"width .4s"}} />
        </div>
        <div style={{width:90,fontSize:"0.7rem",color:"#4dcb8a",fontWeight:700,textAlign:"right",flexShrink:0}}>
          {validVal > 0 ? fmtM(validVal) : <span style={{color:mut}}>-</span>}
        </div>
      </div>
    </div>
  );
}

function PageDashboard({ saved, extras, onEdit }) {
  const [expanded, setExpanded] = useState({});
  const toggle = s => setExpanded(p => ({...p,[s]:!p[s]}));

  // Receita validada: apenas itens salvos com qtd_executar preenchida
  // Receita planilha: todos os itens do QUEUE com qtd da planilha x Pr.Un.
  const validByS = {};
  const planByS  = {};
  const groupsBySistema = {};

  QUEUE.forEach((e,i) => {
    const extra = extras[i] || {...BLANK};
    const s = e.sistema;
    if (!groupsBySistema[s]) groupsBySistema[s] = [];
    groupsBySistema[s].push({...e, extra, savedFlag: saved[i]});

    // receita validada (somente salvo com qtd_executar preenchida)
    if (saved[i]) {
      const rec = calcReceita(e, extra);
      if (rec > 0) validByS[s] = (validByS[s]||0) + rec;
    }
  });

  const allSistemas = [...new Set(QUEUE.map(e=>e.sistema))].sort((a,b)=>(RECEITA_PLAN_SIS[b]||0)-(RECEITA_PLAN_SIS[a]||0));
  const savedCount  = saved.filter(Boolean).length;
  const totalValid  = Object.values(validByS).reduce((a,b)=>a+b,0);
  const maxBar      = Math.max(...allSistemas.map(s=>Math.max(RECEITA_PLAN_SIS[s]||0, validByS[s]||0, 1)));

  const coveragePct = PLAN_TOTAL > 0 ? (totalValid/PLAN_TOTAL*100) : 0;

  return (
    <div style={{maxWidth:960,margin:"0 auto",padding:"24px 16px"}}>

      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:24}}>
        {[
          {label:"Receita Planejada (PARA)",    value:fmtM(PLAN_TOTAL),  color:sub,             note:"DE_PARA col. PARA x Pr.Un."},
          {label:"Receita Validada",             value:fmtM(totalValid),  color:"#4dcb8a",       note:savedCount+" itens salvos"},
          {label:"Cobertura Validada",           value:coveragePct.toFixed(1)+"%", color:coveragePct>50?"#4dcb8a":"#c47e2e", note:"do planejado"},
          {label:"Itens Preenchidos",            value:savedCount+" / "+QUEUE.length, color:tx,  note:Math.round(savedCount/QUEUE.length*100)+"% da fila"},
        ].map(k => (
          <div key={k.label} style={{background:card,border:`1px solid ${brd}`,borderRadius:8,padding:"14px 16px"}}>
            <div style={{fontSize:"0.6rem",color:mut,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:5}}>{k.label}</div>
            <div style={{fontSize:"1.05rem",fontWeight:700,color:k.color,marginBottom:3}}>{k.value}</div>
            <div style={{fontSize:"0.63rem",color:mut}}>{k.note}</div>
          </div>
        ))}
      </div>

      {/* Legenda */}
      <div style={{display:"flex",gap:20,marginBottom:16,fontSize:"0.7rem",color:sub}}>
        <div style={{display:"flex",alignItems:"center",gap:6}}>
          <div style={{width:24,height:8,borderRadius:3,background:"#2e7fb8",opacity:0.4}} />
          <span>Receita Planejada (DE_PARA col. PARA x Pr.Un.)</span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:6}}>
          <div style={{width:24,height:8,borderRadius:3,background:"#4dcb8a"}} />
          <span>Receita Validada (Qtd preenchida x Pr.Un.)</span>
        </div>
      </div>

      {/* Grafico de barras por sistema */}
      <div style={{background:card,border:`1px solid ${brd}`,borderRadius:8,padding:"18px 20px",marginBottom:20}}>
        <div style={{fontSize:"0.68rem",fontWeight:700,color:sub,textTransform:"uppercase",letterSpacing:"0.1em",marginBottom:18}}>
          Comparativo por Sistema
        </div>
        {allSistemas.map(s => (
          <BarGroup
            key={s}
            label={s}
            refVal={RECEITA_PLAN_SIS[s]||0}
            validVal={validByS[s]||0}
            maxVal={maxBar}
            color={sc(s)}
          />
        ))}
      </div>

      {/* Tabela comparativa por sistema */}
      <div style={{background:card,border:`1px solid ${brd}`,borderRadius:8,marginBottom:20,overflow:"hidden"}}>
        {/* Header tabela */}
        <div style={{display:"grid",gridTemplateColumns:"1.8fr 1fr 1fr 80px 80px",gap:8,padding:"10px 18px",background:"#040c14",borderBottom:`1px solid ${brd}`}}>
          {["Sistema","Planejado (PARA)","Validado (preenchido)","Dif. R$","Dif. %"].map(h=>(
            <div key={h} style={{fontSize:"0.62rem",color:mut,textTransform:"uppercase",letterSpacing:"0.07em",textAlign:h.startsWith("Plan")||h.startsWith("Val")||h.startsWith("Dif")?"right":"left"}}>{h}</div>
          ))}
        </div>
        {allSistemas.map((s,ri) => {
          const ref   = RECEITA_PLAN_SIS[s] || 0;
          const valid = validByS[s] || 0;
          const diff  = valid - ref;
          const diffP = ref > 0 ? diff/ref*100 : 0;
          const color = sc(s);
          const isOpen = expanded["t_"+s];
          const rows  = groupsBySistema[s] || [];
          return (
            <div key={s} style={{borderTop:`1px solid ${brd}`}}>
              <div onClick={()=>toggle("t_"+s)}
                style={{display:"grid",gridTemplateColumns:"1.8fr 1fr 1fr 80px 80px",gap:8,padding:"10px 18px",cursor:"pointer",background:ri%2===0?"transparent":"#0a1520",alignItems:"center"}}>
                <div style={{display:"flex",gap:8,alignItems:"center"}}>
                  <div style={{width:8,height:8,borderRadius:2,background:color,flexShrink:0}} />
                  <span style={{fontSize:"0.76rem",color:tx,fontWeight:600}}>{s}</span>
                  <span style={{fontSize:"0.65rem",color:mut,background:"#1e3045",borderRadius:3,padding:"1px 6px"}}>{rows.length} itens</span>
                </div>
                <div style={{fontSize:"0.76rem",color:sub,textAlign:"right"}}>{fmtM(ref)}</div>
                <div style={{fontSize:"0.76rem",color:valid>0?"#4dcb8a":mut,fontWeight:valid>0?700:400,textAlign:"right"}}>{valid>0?fmtM(valid):"-"}</div>
                <div style={{fontSize:"0.72rem",color:diff>0?"#4dcb8a":diff<0?"#e05a5a":mut,textAlign:"right"}}>{valid>0?(diff>=0?"+":"")+fmtM(Math.abs(diff)):"-"}</div>
                <div style={{fontSize:"0.72rem",color:diff>0?"#4dcb8a":diff<0?"#e05a5a":mut,fontWeight:700,textAlign:"right"}}>{valid>0?(diff>=0?"+":"")+diffP.toFixed(1)+"%":"-"}</div>
              </div>

              {/* Detalhes do sistema */}
              {isOpen && (
                <div style={{borderTop:`1px solid ${brd}`,background:"#040c14"}}>
                  <div style={{display:"grid",gridTemplateColumns:"60px 1.4fr 100px 90px 90px 80px 55px",gap:6,padding:"7px 18px",borderBottom:`1px solid ${brd}`}}>
                    {["Item","Descricao","Local","Pr.Un.","Receita Valid.","Status",""].map(h=>(
                      <div key={h} style={{fontSize:"0.6rem",color:mut,textTransform:"uppercase"}}>{h}</div>
                    ))}
                  </div>
                  {rows.map((e,i2) => {
                    const pm   = PRICE_MAP[e.code];
                    const qEx  = parseFloat(e.extra.qtd_executar)||0;
                    const recVal  = pm && qEx>0 ? pm.price*qEx : 0;
                    const statusColor = e.extra.status==="MANTER QUANTIDADE"?"#4dcb8a":e.extra.status==="POSSIVEL REDUCAO"?"#e05a5a":e.extra.status==="POSSIVEL AUMENTO"?"#c47e2e":mut;
                    return (
                      <div key={i2} style={{display:"grid",gridTemplateColumns:"60px 1.4fr 100px 90px 90px 80px 55px",gap:6,padding:"8px 18px",borderTop:`1px solid ${brd}22`,background:e.savedFlag?"#0a1a0a22":"transparent",alignItems:"center"}}>
                        <div style={{fontSize:"0.68rem",color:color,fontWeight:600}}>{e.code}</div>
                        <div>
                          <div style={{fontSize:"0.72rem",color:e.savedFlag?tx:sub}}>{e.label}</div>
                          <div style={{fontSize:"0.63rem",color:mut}}>{(e.extra.descricao_extra||e.descricao||"").slice(0,45)}</div>
                        </div>
                        <div style={{fontSize:"0.68rem",color:sub}}>{e.local||"-"}</div>
                        <div style={{fontSize:"0.68rem",color:sub,textAlign:"right"}}>
                          {pm ? <span>R$ {pm.price.toLocaleString("pt-BR",{minimumFractionDigits:2})}<span style={{fontSize:"0.6rem",color:mut,marginLeft:3}}>/{pm.unit}</span></span> : "-"}
                        </div>
                        <div style={{fontSize:"0.7rem",color:recVal>0?"#4dcb8a":mut,fontWeight:recVal>0?700:400,textAlign:"right"}}>{recVal>0?fmtM(recVal):e.savedFlag?<span style={{color:mut,fontSize:"0.65rem"}}>sem qtd</span>:"-"}</div>
                        <div style={{fontSize:"0.63rem",color:statusColor}}>{e.extra.status||"-"}</div>
                        <div>
                          <Btn v="a" sx={{padding:"2px 7px",fontSize:"0.63rem"}} onClick={()=>onEdit(QUEUE.indexOf(e))}>editar</Btn>
                        </div>
                      </div>
                    );
                  })}
                  {/* Subtotal sistema */}
                  <div style={{display:"grid",gridTemplateColumns:"60px 1.4fr 100px 90px 90px 80px 55px",gap:6,padding:"8px 18px",borderTop:`1px solid ${brd}`,background:"#0d1820"}}>
                    <div style={{gridColumn:"1/4",fontSize:"0.68rem",color:mut,fontWeight:700}}>Subtotal {s}</div>
                    <div style={{fontSize:"0.72rem",color:sub,fontWeight:700,textAlign:"right"}}>{fmtM(ref)}</div>
                    <div style={{fontSize:"0.72rem",color:valid>0?"#4dcb8a":mut,fontWeight:700,textAlign:"right"}}>{valid>0?fmtM(valid):"-"}</div>
                    <div style={{fontSize:"0.68rem",color:diff>0?"#4dcb8a":diff<0?"#e05a5a":mut,fontWeight:700,textAlign:"right",gridColumn:"6/8"}}>
                      {valid>0?(diff>=0?"+":"")+diffP.toFixed(1)+"%":"-"}
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}

        {/* Totais */}
        <div style={{display:"grid",gridTemplateColumns:"1.8fr 1fr 1fr 80px 80px",gap:8,padding:"12px 18px",borderTop:`2px solid ${brd}`,background:"#040c14"}}>
          <div style={{fontSize:"0.75rem",color:tx,fontWeight:700}}>TOTAL GERAL</div>
          <div style={{fontSize:"0.78rem",color:sub,fontWeight:700,textAlign:"right"}}>{fmtM(PLAN_TOTAL)}</div>
          <div style={{fontSize:"0.78rem",color:totalValid>0?"#4dcb8a":mut,fontWeight:700,textAlign:"right"}}>{totalValid>0?fmtM(totalValid):"-"}</div>
          <div style={{fontSize:"0.72rem",color:totalValid>0?(totalValid-PLAN_TOTAL)>=0?"#4dcb8a":"#e05a5a":mut,textAlign:"right",fontWeight:700}}>
            {totalValid>0?(totalValid-PLAN_TOTAL>=0?"+":"")+fmtM(Math.abs(totalValid-PLAN_TOTAL)):"-"}
          </div>
          <div style={{fontSize:"0.72rem",color:totalValid>0?coveragePct>=100?"#4dcb8a":"#c47e2e":mut,fontWeight:700,textAlign:"right"}}>
            {totalValid>0?coveragePct.toFixed(1)+"%":"-"}
          </div>
        </div>
      </div>
    </div>
  );
}

