// Persistencia via Google Sheets - ver saveToSheets / loadFromSheets acima

export default function App() {
  const [page, setPage]           = useState(1);
  const [idx, setIdx]             = useState(0);
  const [extras, setExtras]       = useState(() => QUEUE.map(() => ({...BLANK})));
  const [saved, setSaved]         = useState(() => QUEUE.map(() => false));
  const [filter, setFilter]       = useState("ALL");
  const [jumpTo, setJumpTo]       = useState("");
  const [syncStatus, setSyncStatus] = useState("loading");
  const [baseModal, setBaseModal] = useState(false);  // modal "Usar como base"
  const [baseSearch, setBaseSearch] = useState("");   // filtro dentro do modal
  const topRef    = useRef(null);
  const timerRef  = useRef(null);

  // Load on mount - tenta recuperar preenchimento do Google Sheets
  useEffect(() => {
    async function load() {
      setSyncStatus("loading");
      try {
        const d = await loadFromSheets();
        console.log("[PPU] load keys:", d ? Object.keys(d) : null);
        if (d) {
          if (d.extras && Array.isArray(d.extras)) {
            const base = QUEUE.map((_,i) => d.extras[i] ? {...BLANK,...d.extras[i]} : {...BLANK});
            setExtras(base);
            console.log("[PPU] extras loaded:", d.extras.length);
          }
          if (d.saved && Array.isArray(d.saved)) {
            const baseSaved = QUEUE.map((_,i) => d.saved[i] === true);
            setSaved(baseSaved);
            console.log("[PPU] saved loaded:", d.saved.filter(Boolean).length, "itens");
          }
        }
      } catch(e) { console.warn("[PPU] Erro ao carregar:", e); }
      setSyncStatus("idle");
    }
    load();
  }, []);

  // Debounced auto-save -> Google Sheets
  function persist(newExtras, newSaved) {
    if (timerRef.current) clearTimeout(timerRef.current);
    setSyncStatus("saving");
    timerRef.current = setTimeout(async () => {
      try {
        await saveToSheets({
          extras: newExtras,
          saved:  newSaved,
          ts: new Date().toISOString(),
        });
        setSyncStatus("ok");
        setTimeout(() => setSyncStatus("idle"), 2500);
      } catch(e) {
        console.error("Erro ao salvar:", e);
        setSyncStatus("error");
      }
    }, 700);
  }

  function updateExtras(fn) {
    setExtras(prev => {
      const next = fn(prev);
      // auto-save desabilitado: salvar e feito exclusivamente pelo saveAndNext
      // isso evita que o debounce dispare com saved desatualizado
      return next;
    });
  }
  function updateSaved(fn) {
    setSaved(prev => {
      const next = fn(prev);
      persist(extras, next);
      return next;
    });
  }

  const cur = QUEUE[idx];
  const ext = extras[idx] || {...BLANK};
  const ac  = sc(cur.sistema);

  const sistemas = ["ALL", ...[...new Set(QUEUE.map(e=>e.sistema))].sort()];
  const visIdx = QUEUE.reduce((a,e,i) => { if(filter==="ALL"||e.sistema===filter) a.push(i); return a; },[]);
  const pos = visIdx.indexOf(idx);
  const prev = pos > 0 ? visIdx[pos-1] : null;
  const next = pos < visIdx.length-1 ? visIdx[pos+1] : null;

  const setE = (k,v) => updateExtras(p => { const n=[...p]; n[idx]={...n[idx],[k]:v}; return n; });
  const go   = i => { setIdx(i); topRef.current?.scrollIntoView({behavior:"smooth"}); };

  const saveAndNext = () => {
    const newSaved = [...saved];
    newSaved[idx] = true;
    setSaved(newSaved);
    // Cancela qualquer auto-save pendente e salva imediatamente com saved correto
    if (timerRef.current) { clearTimeout(timerRef.current); timerRef.current = null; }
    setSyncStatus("saving");
    saveToSheets({
      extras: extras,
      saved:  newSaved,
      ts: new Date().toISOString(),
    }).then(() => {
      setSyncStatus("ok");
      setTimeout(() => setSyncStatus("idle"), 2500);
    }).catch(() => setSyncStatus("error"));
    if(next!==null) go(next);
  };

  // Copia o preenchimento do item atual para o item destino escolhido
  function aplicarBase(destIdx) {
    updateExtras(p => {
      const n = [...p];
      n[destIdx] = { ...extras[idx] }; // copia tudo do atual
      return n;
    });
    setBaseModal(false);
    setBaseSearch("");
    go(destIdx);
  }

  // Itens filtrados para o modal de base
  const baseFiltered = QUEUE
    .map((e,i) => ({...e, i}))
    .filter(e => e.i !== idx && (
      baseSearch === "" ||
      e.sistema.toLowerCase().includes(baseSearch.toLowerCase()) ||
      e.label.toLowerCase().includes(baseSearch.toLowerCase()) ||
      e.descricao.toLowerCase().includes(baseSearch.toLowerCase()) ||
      e.code.toLowerCase().includes(baseSearch.toLowerCase())
    ))
    .slice(0, 60);

  const statusDot = {
    loading: {color:"#c47e2e", label:"Carregando..."},
    saving:  {color:"#c47e2e", label:"Salvando..."},
    ok:      {color:"#4dcb8a", label:"Salvo"},
    error:   {color:"#e05a5a", label:"Erro ao salvar"},
    idle:    {color:"#4a6a85", label:""},
  }[syncStatus] || {color:"#4a6a85",label:""};

  const savedCount = saved.filter(Boolean).length;
  const pct = Math.round(savedCount/QUEUE.length*100);

  const pm = PRICE_MAP[cur.code];
  const qtdEx  = parseFloat(ext.qtd_executar) || 0;
  const qtdRef = parseFloat(cur.qtd) || 0;
  const qtdCalc = qtdEx > 0 ? qtdEx : qtdRef;
  const receita = pm && qtdCalc > 0 ? pm.price * qtdCalc : null;
  const subTotal = ext.subcontratadas.reduce((s,r)=>s+(parseFloat(r.qtd||0)*parseFloat(r.vunit||0)),0);

  const totalReceita = QUEUE.reduce((acc,e,i) => acc + calcReceita(e, extras[i]||BLANK) * (saved[i]?1:0), 0);

  return (
    <div ref={topRef} style={{fontFamily:"monospace",background:bg,minHeight:"100vh",color:tx}}>

      {/* Navbar global */}
      <div style={{background:"#040c14",borderBottom:`1px solid ${brd}`,padding:"0 20px",position:"sticky",top:0,zIndex:100}}>
        <div style={{maxWidth:900,margin:"0 auto"}}>
          {/* Titulo + progress */}
          <div style={{display:"flex",flexWrap:"wrap",gap:10,alignItems:"center",justifyContent:"space-between",paddingTop:10,paddingBottom:6}}>
            <div>
              <div style={{fontSize:"0.9rem",fontWeight:700,color:tx}}>FORMULARIO DE LEVANTAMENTO PPU</div>
              <div style={{fontSize:"0.62rem",color:mut}}>RTT Solucoes Industriais - DADOS_SISTEMAS</div>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              {syncStatus !== "idle" && (
                <div style={{display:"flex",alignItems:"center",gap:5,fontSize:"0.68rem",color:statusDot.color}}>
                  <div style={{width:7,height:7,borderRadius:"50%",background:statusDot.color,animation:syncStatus==="saving"?"pulse 1s infinite":""}} />
                  {statusDot.label}
                </div>
              )}
              <div style={{fontSize:"0.7rem",color:sub}}>
                <span style={{color:tx,fontWeight:700}}>{savedCount}</span>/{QUEUE.length} salvos
                <span style={{marginLeft:8,color:"#4dcb8a",fontWeight:700}}>{pct}%</span>
              </div>
              <div style={{width:90,height:5,background:"#1e3045",borderRadius:3,overflow:"hidden"}}>
                <div style={{width:`${pct}%`,height:"100%",background:"#4dcb8a",transition:"width .3s"}} />
              </div>
            </div>
          </div>
          {/* Abas */}
          <div style={{display:"flex",gap:0}}>
            {[{n:1,lbl:"Pagina 1 - Levantamento"},{n:2,lbl:"Pagina 2 - Consolidado"}].map(t => (
              <div key={t.n} onClick={()=>setPage(t.n)}
                style={{padding:"8px 20px",fontSize:"0.75rem",fontWeight:700,cursor:"pointer",borderBottom:`2px solid ${page===t.n?"#4dcb8a":"transparent"}`,color:page===t.n?"#4dcb8a":sub,transition:"all .15s",letterSpacing:"0.04em"}}>
                {t.lbl}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* - Pagina 2 - */}
      {page === 2 && (
        <PageDashboard saved={saved} extras={extras} onEdit={handleEditFromDash} />
      )}

      {/* - Pagina 1 - */}
      {page === 1 && (
        <div>
          {/* Sub-header: filtro + jump */}
          <div style={{background:"#040c14",borderBottom:`1px solid ${brd}`,padding:"8px 20px"}}>
            <div style={{maxWidth:900,margin:"0 auto",display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
              <select value={filter} onChange={e=>{setFilter(e.target.value); const fi=QUEUE.findIndex(q=>e.target.value==="ALL"||q.sistema===e.target.value); if(fi>=0) setIdx(fi);}}
                style={{background:"#1e3045",border:"none",borderRadius:6,padding:"5px 10px",color:tx,fontSize:"0.75rem",cursor:"pointer",outline:"none"}}>
                {sistemas.map(s=><option key={s} value={s}>{s==="ALL"?"Todos os Sistemas":s}</option>)}
              </select>
              <div style={{display:"flex",gap:4,marginLeft:"auto"}}>
                <Inp sx={{width:60,fontSize:"0.74rem",padding:"5px 8px"}} type="number" value={jumpTo} placeholder="nr" onChange={e=>setJumpTo(e.target.value)} onKeyDown={e=>e.key==="Enter"&&(()=>{const n=parseInt(jumpTo)-1; if(n>=0&&n<QUEUE.length){setIdx(n);setJumpTo("");topRef.current?.scrollIntoView({behavior:"smooth"});}})()}/>
                <Btn v="g" sx={{padding:"5px 10px",fontSize:"0.74rem"}} onClick={()=>{const n=parseInt(jumpTo)-1; if(n>=0&&n<QUEUE.length){setIdx(n);setJumpTo("");topRef.current?.scrollIntoView({behavior:"smooth"});}}}>ir</Btn>
              </div>
            </div>
          </div>

          <div style={{maxWidth:900,margin:"0 auto",padding:"18px 16px"}}>
            {/* Nav */}
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14}}>
              <Btn v="g" sx={{padding:"6px 12px",fontSize:"0.8rem"}} onClick={()=>prev!==null&&go(prev)} disabled={prev===null}>Anterior</Btn>
              <div style={{flex:1,textAlign:"center",fontSize:"0.7rem",color:mut}}>
                <span style={{color:ac,fontWeight:700}}>{pos+1}</span> de <span style={{fontWeight:700,color:tx}}>{visIdx.length}</span>
                {filter!=="ALL" && <span> ({filter})</span>}
                {saved[idx] && <span style={{marginLeft:8,color:"#4dcb8a",fontSize:"0.68rem"}}>[salvo]</span>}
              </div>
              <Btn v="g" sx={{padding:"6px 12px",fontSize:"0.8rem"}} onClick={()=>next!==null&&go(next)} disabled={next===null}>Proximo</Btn>
            </div>

            {/* Card do item */}
            <div style={{background:card,border:`1px solid ${brd}`,borderTop:`4px solid ${ac}`,borderRadius:10,padding:"18px 20px",marginBottom:18}}>
              <div style={{display:"flex",alignItems:"flex-start",gap:8,marginBottom:14,flexWrap:"wrap"}}>
                <div style={{background:ac+"22",border:`1px solid ${ac}44`,borderRadius:6,padding:"4px 10px",fontSize:"0.68rem",fontWeight:700,color:ac}}>{cur.sistema}</div>
                {cur.local && <div style={{background:"#1e3045",borderRadius:6,padding:"4px 10px",fontSize:"0.68rem",color:sub}}>{cur.local}</div>}
                <div style={{background:"#1e3045",borderRadius:6,padding:"4px 10px",fontSize:"0.68rem",color:sub}}>Item {cur.code}</div>
                {cur.status && <div style={{marginLeft:"auto",background:"#1a3d2e",borderRadius:6,padding:"4px 10px",fontSize:"0.68rem",color:"#4dcb8a"}}>{cur.status}</div>}
              </div>

              <div style={{fontSize:"0.78rem",fontWeight:700,color:tx,marginBottom:4}}>{cur.label}</div>
              <div style={{fontSize:"0.8rem",color:sub,marginBottom:14,lineHeight:1.5,minHeight:32}}>
                {cur.descricao || <span style={{color:mut,fontStyle:"italic"}}>Sem descricao</span>}
              </div>

              {/* Bloco receita */}
              <div style={{background:"#040c14",border:`1px solid ${ac}33`,borderRadius:8,padding:"10px 14px",marginBottom:14,display:"flex",flexWrap:"wrap",gap:8}}>
                {pm ? (
                  <>
                    <div style={{flex:1,minWidth:130}}>
                      <div style={{fontSize:"0.62rem",color:mut,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Pr. Unit. (DE_PARA)</div>
                      <div style={{fontSize:"0.9rem",fontWeight:700,color:sub}}>
                        R$ {fmt(pm.price)}
                        <span style={{fontSize:"0.67rem",fontWeight:400,color:mut,marginLeft:5}}>/{pm.unit}</span>
                      </div>
                    </div>
                    <div style={{flex:1,minWidth:110}}>
                      <div style={{fontSize:"0.62rem",color:mut,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Qtd {qtdEx>0?"(digitada)":"(planilha)"}</div>
                      <div style={{fontSize:"0.9rem",fontWeight:700,color:qtdEx>0?"#c47e2e":sub}}>
                        {qtdCalc>0 ? qtdCalc.toLocaleString("pt-BR") : <span style={{color:mut,fontStyle:"italic",fontSize:"0.78rem"}}>---</span>}
                        {qtdCalc>0 && <span style={{fontSize:"0.67rem",color:mut,marginLeft:4}}>{pm.unit}</span>}
                      </div>
                    </div>
                    <div style={{flex:1.5,minWidth:160,borderLeft:`1px solid ${brd}`,paddingLeft:14}}>
                      <div style={{fontSize:"0.62rem",color:mut,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3}}>Receita Estimada</div>
                      {receita !== null
                        ? <div style={{fontSize:"1rem",fontWeight:700,color:"#4dcb8a"}}>R$ {fmt(receita)}</div>
                        : <div style={{fontSize:"0.76rem",color:mut,fontStyle:"italic",paddingTop:4}}>Qtd nao informada</div>
                      }
                      {qtdEx>0 && qtdRef>0 && Math.abs(qtdEx-qtdRef)>0.001 && (
                        <div style={{fontSize:"0.64rem",color:mut,marginTop:2}}>Ref. planilha: R$ {fmt(pm.price*qtdRef)}</div>
                      )}
                    </div>
                  </>
                ) : (
                  <div style={{fontSize:"0.72rem",color:mut,fontStyle:"italic"}}>Preco unitario nao localizado na DE_PARA para o item {cur.code}</div>
                )}
              </div>

              {/* Campos */}
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:12}}>
                <div><Lbl>Qtd a Executar</Lbl><Inp value={ext.qtd_executar} placeholder={cur.qtd||"0"} onChange={e=>setE("qtd_executar",e.target.value)} /></div>
                <div><Lbl>Linha do Planejamento</Lbl><Inp value={ext.linha_plan} placeholder="ex: 10 a 18" onChange={e=>setE("linha_plan",e.target.value)} /></div>
                <div>
                  <Lbl>Status</Lbl>
                  <Sel value={ext.status} onChange={e=>setE("status",e.target.value)}>
                    <option value="">-- selecione --</option>
                    {STATUS_OPT.map(s=><option key={s} value={s}>{s}</option>)}
                  </Sel>
                </div>
              </div>
              <div><Lbl>Descricao Complementar</Lbl><Txt value={ext.descricao_extra} placeholder="Detalhes adicionais..." onChange={e=>setE("descricao_extra",e.target.value)} sx={{minHeight:48}} /></div>
            </div>

            {/* Secoes com dados reais e busca */}
            <SmartSection title="Mao de Obra"        ac="#3b88c3" items={ext.mao_de_obra}  onChange={v=>setE("mao_de_obra",v)}  sectionType="mo"      addLbl="+ Funcao" />
            <SmartSection title="Equipamentos"       ac="#2e9c8c" items={ext.equipamentos} onChange={v=>setE("equipamentos",v)} sectionType="eq"      addLbl="+ Equipamento" />
            <SmartSection title="Insumos"            ac="#8c6fd4" items={ext.insumos}      onChange={v=>setE("insumos",v)}      sectionType="estoque" addLbl="+ Insumo" />
            <SmartSection title="Material de Aplicacao" ac="#c47e2e" items={ext.materiais} onChange={v=>setE("materiais",v)}    sectionType="estoque" addLbl="+ Material" />

            {/* Subcontratadas */}
            <div style={{background:card,border:`1px solid ${brd}`,borderLeft:"3px solid #c44a4a",borderRadius:8,padding:"12px 16px",marginBottom:12}}>
              <div style={{fontSize:"0.68rem",fontWeight:700,color:"#c44a4a",letterSpacing:"0.1em",textTransform:"uppercase",marginBottom:10}}>Subcontratadas</div>
              <DynList items={ext.subcontratadas} onChange={v=>setE("subcontratadas",v)}
                cols={[{k:"empresa",lbl:"Empresa",ph:"Razao social...",w:"1.2fr"},{k:"atividade",lbl:"Atividade",ph:"Descricao...",w:"2fr"},{k:"qtd",lbl:"Qtd",type:"number",ph:"0",w:"65px"},{k:"vunit",lbl:"Valor Unit. R$",type:"number",ph:"0,00",w:"110px"}]}
                addLbl="Subcontratada" />
              {ext.subcontratadas.length>0 && (
                <div style={{display:"flex",justifyContent:"flex-end",marginTop:8}}>
                  <div style={{background:"#1e3045",borderRadius:6,padding:"5px 14px",fontSize:"0.78rem"}}>
                    <span style={{color:sub}}>Total: </span>
                    <span style={{color:"#c44a4a",fontWeight:700}}>R$ {fmt(subTotal)}</span>
                  </div>
                </div>
              )}
            </div>

            {/* Observacoes */}
            <div style={{background:card,border:`1px solid ${brd}`,borderLeft:`3px solid ${mut}`,borderRadius:8,padding:"12px 16px",marginBottom:18}}>
              <Lbl>Observacoes Gerais</Lbl>
              <Txt value={ext.observacao} placeholder="Restricoes de acesso, condicionantes de seguranca..." onChange={e=>setE("observacao",e.target.value)} sx={{minHeight:60}} />
            </div>

            {/* Acoes */}
            <div style={{display:"flex",gap:10,justifyContent:"space-between",flexWrap:"wrap",marginBottom:32}}>
              <div style={{display:"flex",gap:8}}>
                <Btn v="g" onClick={()=>updateExtras(p=>{ const n=[...p]; n[idx]={...BLANK}; return n; })}>Limpar</Btn>
                <Btn v="o" onClick={()=>next!==null&&go(next)} disabled={next===null}>Pular</Btn>
                <Btn v="a" onClick={()=>{setBaseModal(true);setBaseSearch("");}}>Usar como base</Btn>
              </div>
              <div style={{display:"flex",gap:8,alignItems:"center"}}>
                {totalReceita>0 && <div style={{fontSize:"0.75rem",color:sub}}>Total salvo: <span style={{color:"#4dcb8a",fontWeight:700}}>R$ {fmtN(totalReceita)}</span></div>}
                <Btn v="s" onClick={saveAndNext} sx={{padding:"10px 28px",fontSize:"0.85rem"}}>
                  {next!==null ? "Salvar e Avancar" : "Salvar"}
                </Btn>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal: Usar como base */}
      {baseModal && (
        <div style={{position:"fixed",inset:0,background:"#000a",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
          <div style={{background:card,border:`1px solid ${brd}`,borderRadius:12,width:"100%",maxWidth:620,maxHeight:"80vh",display:"flex",flexDirection:"column",overflow:"hidden"}}>
            <div style={{padding:"14px 18px",borderBottom:`1px solid ${brd}`,display:"flex",justifyContent:"space-between",alignItems:"center",flexShrink:0}}>
              <div>
                <div style={{fontSize:"0.85rem",fontWeight:700,color:tx}}>Usar como base</div>
                <div style={{fontSize:"0.68rem",color:mut,marginTop:2}}>
                  Copiando de: <span style={{color:ac,fontWeight:700}}>[{cur.code}] {cur.label.slice(0,40)}</span>
                </div>
              </div>
              <Btn v="g" sx={{padding:"4px 10px",fontSize:"0.78rem"}} onClick={()=>setBaseModal(false)}>fechar</Btn>
            </div>
            <div style={{padding:"10px 18px",borderBottom:`1px solid ${brd}`,flexShrink:0}}>
              <Inp
                value={baseSearch}
                placeholder="Filtrar por sistema, servico, codigo ou descricao..."
                onChange={e=>setBaseSearch(e.target.value)}
                sx={{fontSize:"0.8rem"}} />
              <div style={{fontSize:"0.65rem",color:mut,marginTop:4}}>
                {baseSearch===""?`Mostrando os primeiros 60 de ${QUEUE.length-1} itens - digite para filtrar`:`${baseFiltered.length} resultado(s)`}
              </div>
            </div>
            <div style={{overflowY:"auto",flex:1}}>
              {baseFiltered.map(e=>(
                <div key={e.i}
                  onClick={()=>aplicarBase(e.i)}
                  style={{padding:"10px 18px",cursor:"pointer",borderBottom:`1px solid ${brd}22`,display:"flex",gap:10,alignItems:"flex-start"}}
                  onMouseOver={ev=>ev.currentTarget.style.background="#1e3045"}
                  onMouseOut={ev=>ev.currentTarget.style.background="transparent"}>
                  <div style={{flexShrink:0,minWidth:90}}>
                    <div style={{fontSize:"0.64rem",color:sc(e.sistema),fontWeight:700,background:sc(e.sistema)+"22",borderRadius:4,padding:"2px 6px",marginBottom:3}}>{e.sistema}</div>
                    <div style={{fontSize:"0.68rem",color:mut}}>item {e.code}</div>
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:"0.76rem",color:saved[e.i]?"#4dcb8a":tx,fontWeight:saved[e.i]?700:400}}>{e.label}</div>
                    <div style={{fontSize:"0.65rem",color:mut,marginTop:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{e.local}{e.descricao?" - "+e.descricao.slice(0,50):""}</div>
                  </div>
                  {saved[e.i]&&<div style={{fontSize:"0.62rem",color:"#4dcb8a",flexShrink:0,paddingTop:2}}>preenchido</div>}
                </div>
              ))}
            </div>
            <div style={{padding:"8px 18px",borderTop:`1px solid ${brd}`,flexShrink:0,fontSize:"0.65rem",color:mut}}>
              Clique no item de destino para copiar o preenchimento atual para ele e navegar ate la.
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
